INSERT INTO articles (id, title, slug, lead, content, category_id, status, published_at, views) VALUES
(
  'e1000000-0000-4000-a000-000000000001',
  'В Ингушетии высадят белую акацию вдоль 28 километров дорог',
  'v-ingushetii-vysadyat-beluyu-akaciyu-vdol-28-km-dorog',
  'Министерство природных ресурсов республики планирует высадить около 12 тысяч деревьев белой акации вдоль автомобильных дорог в рамках Года экологии.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В Республике Ингушетия стартовала масштабная акция по озеленению автомобильных дорог. По данным министра природных ресурсов и экологии региона Микаила Мизиева, до конца 2026 года планируется высадить около 12 тысяч саженцев белой акации вдоль 28 километров дорог."}]},{"type":"paragraph","content":[{"type":"text","text":"На 7 апреля работы выполнены на участке протяжённостью 5 километров. Выбор именно белой акации обусловлен климатическими условиями республики — на большей части дорог наблюдаются засушливость и высокая солнечная нагрузка, а акация хорошо адаптирована к таким условиям."}]},{"type":"paragraph","content":[{"type":"text","text":"Министр также отметил, что в республике уже высажено 72 тысячи саженцев, что на 4 тысячи больше, чем годом ранее. Работы ведутся в рамках акции «Сад памяти» с упором на посадку ясеня. Озеленение дорог является частью комплексной программы Года экологии в Ингушетии."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-04-08T09:00:00Z',
  45
),
(
  'e1000000-0000-4000-a000-000000000002',
  'В Ингушетии построят новый реабилитационный центр для детей за 1,5 млрд рублей',
  'v-ingushetii-postroyat-novyj-reabilitacionnyj-centr-dlya-detej',
  'Действующий центр в Троицком может принять лишь 50 детей, хотя в помощи нуждаются более 300. Власти подготовили проект строительства нового современного учреждения.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В Троицком реабилитационном центре для несовершеннолетних сложилась критическая ситуация: учреждение может принять только 50 детей, хотя реально в помощи нуждаются от 300 до 350 ребят. Из-за нехватки мест самые тяжёлые случаи приходится рассматривать на уровне подопечных советов, но даже это не решает проблему."}]},{"type":"paragraph","content":[{"type":"text","text":"Для исправления ситуации власти Ингушетии подготовили проект строительства нового современного центра стоимостью около 1,5 миллиарда рублей. Вся проектная документация уже направлена в федеральные органы, а глава республики обсудил проект с вице-премьером РФ Татьяной Голиковой."}]},{"type":"paragraph","content":[{"type":"text","text":"Ожидается, что финансирование будет выделено в 2026 году, а строительство стартует в 2027-м. Новый центр даст шанс на полноценную реабилитацию сотням детей, которые сейчас остаются без необходимой поддержки."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-04-07T18:00:00Z',
  87
),
(
  'e1000000-0000-4000-a000-000000000003',
  'В Назрани продолжается активное благоустройство городских пространств',
  'v-nazrani-prodolzhaetsya-blagoustrojstvo-gorodskih-prostranstv',
  'Глава Назрани Руслан Оздоев подчеркнул, что обновление городской инфраструктуры остаётся одним из ключевых направлений работы.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В Назрани продолжается активная фаза благоустройства городских пространств. Работа ведётся последовательно и охватывает всё больше важных участков городской инфраструктуры."}]},{"type":"paragraph","content":[{"type":"text","text":"В настоящее время продолжается обустройство и обновление парковочной зоны по улице Гайрбек Хаджи. Проект реализуется при поддержке одного из предпринимателей Назрани. В ближайшее время планируется обустроить удобный и безопасный въезд на территорию станции скорой медицинской помощи, что особенно важно для оперативности экстренных служб."}]},{"type":"paragraph","content":[{"type":"text","text":"Далее запланирован ремонт стоянки по улице Муталиева, а также строительство тротуара, который повысит уровень безопасности и комфорта для пешеходов."}]},{"type":"paragraph","content":[{"type":"text","text":"Глава Назрани Руслан Оздоев подчеркнул, что благоустройство городской среды и прилегающих территорий к социальным объектам остаётся одним из ключевых направлений работы. По его словам, важно комплексно подходить к развитию городской инфраструктуры, создавая комфортные условия для всех жителей."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-04-08T05:00:00Z',
  62
),
(
  'e1000000-0000-4000-a000-000000000004',
  'В Ингушетии появится завод по производству септиков',
  'v-ingushetii-poyavitsya-zavod-po-proizvodstvu-septikov',
  'Строительство завода связано с необходимостью отказа от выгребных ям, загрязняющих подземные источники воды.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В Республике Ингушетия появится завод по производству септиков. Для реализации проекта уже выделен земельный участок, а инвестор прошёл конкурсный отбор. Строительство займёт два-три года."}]},{"type":"paragraph","content":[{"type":"text","text":"По словам министра природных ресурсов и экологии региона Микаила Мизиева, строительство завода связано с необходимостью отказа от выгребных ям, которые загрязняют подземные источники воды. Переход на современные септики позволит значительно улучшить экологическую ситуацию в республике."}]},{"type":"paragraph","content":[{"type":"text","text":"Реализация проекта обеспечит чистоту питьевой воды для жителей Ингушетии и создаст новые рабочие места в промышленном секторе. Это ещё один шаг в рамках комплексной экологической программы региона."}]}]}',
  'c1000000-0000-4000-a000-000000000002',
  'published',
  '2026-04-07T16:00:00Z',
  53
),
(
  'e1000000-0000-4000-a000-000000000005',
  'Представлен масштабный проект развития Малгобекского парка на 26,5 гектара',
  'predstavlen-proekt-razvitiya-malgobeksokogo-parka',
  'Парк имени Серго Орджоникидзе планируется превратить в современный всесезонный кластер с пятью тематическими зонами.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Представлен масштабный проект развития парка культуры и отдыха имени Серго Орджоникидзе в городе Малгобек. Территория парка составляет 26,5 гектара, а архитектурная стилистика предполагает сочетание современной урбанистики с элементами ингушского национального зодчества."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Пять тематических зон"}]},{"type":"paragraph","content":[{"type":"text","text":"Проект предусматривает создание пяти функциональных зон: «Историческое сердце» с парадным входом и Аллеей Славы, «Гастрономическая терраса» с фудкортом, детская развлекательная зона, зона экстрима и адреналина с трансформацией существующей площадки аттракционов, а также аквазона."}]},{"type":"paragraph","content":[{"type":"text","text":"Среди главных принципов проекта — сохранение памяти города Воинской Славы, круглогодичность функционирования и создание доступной среды для маломобильных групп населения."}]},{"type":"paragraph","content":[{"type":"text","text":"По замыслу авторов, обновлённый парк сможет стать центром притяжения не только для жителей Ингушетии, но и для гостей из соседних республик — Северной Осетии и Кабардино-Балкарии."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-04-07T12:00:00Z',
  134
),
(
  'e1000000-0000-4000-a000-000000000006',
  'Ингушский борец Хамзат Аушев завоевал бронзу на Первенстве России в Уфе',
  'ingushskij-borec-khamzat-aushev-bronza-pervenstvo-rossii',
  'Воспитанник ингушской школы греко-римской борьбы стал третьим в весовой категории до 41 кг среди 600 участников.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Ингушский борец греко-римского стиля Хамзат Аушев завоевал бронзовую медаль на Первенстве России, которое прошло в Уфе. Об этом сообщила пресс-служба Федерации спортивной борьбы Республики Ингушетия."}]},{"type":"paragraph","content":[{"type":"text","text":"В соревнованиях приняли участие порядка 600 юношей до 16 лет со всей России. Воспитанник ингушской школы греко-римской борьбы Хамзат Аушев стал обладателем третьего места в весовой категории до 41 килограмма."}]},{"type":"paragraph","content":[{"type":"text","text":"Наставником бронзового призёра является тренер Ислам Дошхаклоев из спортивной школы Али-Юрта. Успех молодого спортсмена подтверждает высокий уровень подготовки борцов в республике и перспективы развития греко-римской борьбы в Ингушетии."}]}]}',
  'c1000000-0000-4000-a000-000000000005',
  'published',
  '2026-04-07T14:00:00Z',
  98
),
(
  'e1000000-0000-4000-a000-000000000007',
  'Уроженец Ингушетии Азраиль Пошев возглавил государственную экзаменационную комиссию в МГСУ',
  'azrail-poshev-vozglavil-gek-v-mgsu',
  'Генеральный директор IT-компании BIM ENVELOP назначен председателем ГЭК в ведущем строительном вузе страны.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Приказом ректора НИУ МГСУ профессора Павла Акимова уроженец Ингушетии Азраиль Пошев назначен председателем государственной экзаменационной комиссии в ведущем строительном вузе страны на 2026 год."}]},{"type":"paragraph","content":[{"type":"text","text":"Азраиль Пошев является генеральным директором аккредитованной IT-компании BIM ENVELOP, имеющей лицензию на образовательную деятельность. При его непосредственном участии итоговую аттестацию будут проходить студенты по направлениям «Информационное моделирование в строительстве», «Искусственный интеллект в строительстве» и «Автоматизированные системы обработки информации в строительстве»."}]},{"type":"paragraph","content":[{"type":"text","text":"Назначение связано с задачей подготовки кадров в условиях нарастающего дефицита специалистов в сфере технологий информационного моделирования. Участие в работе ГЭК позволит передать практический опыт будущим специалистам и внести вклад в развитие цифровой отрасли строительства."}]}]}',
  'c1000000-0000-4000-a000-000000000009',
  'published',
  '2026-04-06T15:00:00Z',
  76
),
(
  'e1000000-0000-4000-a000-000000000008',
  'УФАС вынесло 30 предупреждений мэрии Назрани за нарушения в сфере рекламы',
  'ufas-vyneslo-30-preduprezhdenij-merii-nazrani',
  'Антимонопольщики выявили неправомерное заключение договоров на размещение рекламных конструкций по цене 15 рублей в квартал.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Управление Федеральной антимонопольной службы по Республике Ингушетия направило в адрес администрации Назрани 30 предупреждений о прекращении действий, содержащих признаки нарушения Закона о защите конкуренции."}]},{"type":"paragraph","content":[{"type":"text","text":"В ходе проверок антимонопольщики установили, что на основании неправомерно заключённых в 2012 году договоров местная администрация выдала дополнительные разрешения на размещение рекламных конструкций. Большинство договоров аренды заключались по цене 15 рублей в квартал, что само по себе является признаком нарушения."}]},{"type":"paragraph","content":[{"type":"text","text":"Кроме того, договоры были заключены с превышением допустимого срока аренды до десяти лет в соответствии с Земельным кодексом РФ, тогда как порядок их заключения устанавливается законодательством о рекламе. По мнению специалистов УФАС, подобные действия создают преференции отдельным участникам рынка и ограничивают конкуренцию."}]}]}',
  'c1000000-0000-4000-a000-000000000001',
  'published',
  '2026-04-08T08:00:00Z',
  41
),
(
  'e1000000-0000-4000-a000-000000000009',
  'Жители Ингушетии направили 16 фур питьевой воды в пострадавший Дагестан',
  'zhiteli-ingushetii-napravili-16-fur-vody-v-dagestan',
  'Гуманитарная помощь из Ингушетии прибыла в Дагестан, в том числе в посёлок Новый Хушет.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Жители Республики Ингушетия собрали и направили 16 фур бутилированной питьевой воды в Дагестан, пострадавший от чрезвычайной ситуации. Гуманитарный груз прибыл в несколько населённых пунктов, в том числе в посёлок Новый Хушет."}]},{"type":"paragraph","content":[{"type":"text","text":"Сбор гуманитарной помощи был организован жителями республики в кратчайшие сроки. Инициатива объединила людей из разных городов и сёл Ингушетии, продемонстрировав традиционную взаимовыручку и братские связи между народами Северного Кавказа."}]},{"type":"paragraph","content":[{"type":"text","text":"Помощь соседнему региону стала ещё одним подтверждением крепких межрегиональных связей и готовности ингушского народа поддержать соседей в трудную минуту."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-04-07T20:00:00Z',
  112
);

